const {
    battery,
    temperature,
	illuminance,
	soilMoisture,
	reporting,
} = require('zigbee-herdsman-converters/lib/modernExtend');

const soilMoistureReporting = {min: 10, max: 1800, change: 400};
const temperatureReporting = {min: 10, max: 1800, change: 10};
const illuminanceReporting = {min: 10, max: 1800, change: 500};
const batteryReporting = {min: 10, max: 1800, change: 10};

const definition = {
        zigbeeModel: ['DIYRuZ_FW2340R5'],
        model: 'DIYRuZ_FW2340R5',
        vendor: 'DIYRuZ',
        description: '[FW](https://github.com/koptserg/flower_CC2340R5_RGE)',
        ota: true,
		icon: 'data:image/png;base64,',
    extend: [
        soilMoisture({
			reporting: soilMoistureReporting,
            access: "STATE",
        }),
        temperature({
			reporting: temperatureReporting,
            access: "STATE",
        }),
        illuminance({
			reporting: illuminanceReporting,
            access: "STATE",
        }),
        battery({
            percentage: true,
            lowStatus: false,
            voltage: false,
            percentageReporting: true,
            percentageReportingConfig: batteryReporting,
        }),
     ],
    };

module.exports = definition;